import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { permissionsApi, PermissionData } from '../api/permissions';
import { studentsApi } from '../api/students';
import { settingsApi, StageConfigData } from '../api/settings';
import { showSuccess, showError } from '../components/shared/Toast';
import { SETTINGS_STAGES } from '../utils/constants';

interface PermissionRow {
  id: number;
  studentId: number;
  studentNumber: string;
  studentName: string;
  grade: string;
  className: string;
  stage: string;
  mobile: string;
  exitTime: string;
  reason: string;
  receiver: string;
  supervisor: string;
  hijriDate: string;
  recordedBy: string;
  recordedAt: string;
  confirmationTime: string;
  isSent: boolean;
}

interface StudentOption {
  id: number;
  studentNumber: string;
  name: string;
  stage: string;
  grade: string;
  className: string;
}

const REASONS = ['مرض', 'مراجعة طبية', 'ظروف عائلية', 'مراجعة حكومية', 'أخرى'];

const PermissionsPage: React.FC = () => {
  const [records, setRecords] = useState<PermissionRow[]>([]);
  const [stages, setStages] = useState<StageConfigData[]>([]);
  const [loading, setLoading] = useState(true);
  const [stageFilter, setStageFilter] = useState('__all__');
  const [search, setSearch] = useState('');
  const [modalOpen, setModalOpen] = useState(false);
  const [confirmDelete, setConfirmDelete] = useState<PermissionRow | null>(null);

  const enabledStages = useMemo(() =>
    stages.filter((s) => s.isEnabled && s.grades.some((g) => g.isEnabled && g.classCount > 0)),
    [stages]
  );

  const loadData = useCallback(async () => {
    setLoading(true);
    try {
      const [rRes, sRes] = await Promise.all([permissionsApi.getAll(), settingsApi.getStructure()]);
      if (rRes.data?.data) setRecords(rRes.data.data);
      if (sRes.data?.data?.stages) setStages(Array.isArray(sRes.data.data.stages) ? sRes.data.data.stages : []);
    } catch { /* empty */ }
    finally { setLoading(false); }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const filtered = useMemo(() => {
    let list = records;
    if (stageFilter !== '__all__') list = list.filter(r => r.stage === stageFilter);
    if (search.trim()) {
      const q = search.trim().toLowerCase();
      list = list.filter(r => r.studentName.toLowerCase().includes(q) || r.studentNumber.includes(q));
    }
    return list;
  }, [records, stageFilter, search]);

  const handleDelete = async () => {
    if (!confirmDelete) return;
    try {
      await permissionsApi.delete(confirmDelete.id);
      showSuccess('تم حذف السجل بنجاح');
      setConfirmDelete(null);
      loadData();
    } catch { showError('فشل حذف السجل'); }
  };

  const stageLabel = (id: string) => SETTINGS_STAGES.find(s => s.id === id)?.name || id;

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
        <h1 style={{ fontSize: '24px', fontWeight: 800, color: '#111', margin: 0 }}>الاستئذان</h1>
        <button onClick={() => setModalOpen(true)} style={{
          padding: '10px 24px', background: '#7c3aed', color: '#fff', border: 'none',
          borderRadius: '10px', fontWeight: 700, fontSize: '14px', cursor: 'pointer',
        }}>+ تسجيل استئذان</button>
      </div>

      {/* Stats */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: '16px', marginBottom: '24px' }}>
        <StatCard label="إجمالي الاستئذان" value={records.length} color="#7c3aed" />
        <StatCard label="اليوم" value={records.filter(r => {
          const d = new Date(r.recordedAt);
          const today = new Date();
          return d.toDateString() === today.toDateString();
        }).length} color="#2563eb" />
      </div>

      {/* Filters */}
      <div style={{ display: 'flex', gap: '8px', marginBottom: '16px', flexWrap: 'wrap', alignItems: 'center' }}>
        <button onClick={() => setStageFilter('__all__')} style={filterBtnStyle(stageFilter === '__all__')}>الكل</button>
        {enabledStages.map(s => (
          <button key={s.stage} onClick={() => setStageFilter(s.stage)} style={filterBtnStyle(stageFilter === s.stage)}>{stageLabel(s.stage)}</button>
        ))}
        <input type="text" placeholder="بحث..." value={search} onChange={e => setSearch(e.target.value)}
          style={{ marginRight: 'auto', padding: '8px 16px', border: '1px solid #d1d5db', borderRadius: '8px', fontSize: '14px', minWidth: '200px' }} />
      </div>

      {/* Table */}
      {loading ? (
        <div style={{ textAlign: 'center', padding: '40px', color: '#9ca3af' }}>جاري التحميل...</div>
      ) : filtered.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '40px', color: '#9ca3af' }}>لا توجد سجلات</div>
      ) : (
        <div style={{ background: '#fff', borderRadius: '12px', border: '1px solid #e5e7eb', overflow: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '14px' }}>
            <thead>
              <tr style={{ background: '#f9fafb', borderBottom: '2px solid #e5e7eb' }}>
                <th style={thStyle}>#</th>
                <th style={thStyle}>الطالب</th>
                <th style={thStyle}>الصف</th>
                <th style={thStyle}>وقت الخروج</th>
                <th style={thStyle}>السبب</th>
                <th style={thStyle}>المستلم</th>
                <th style={thStyle}>التاريخ</th>
                <th style={thStyle}>إجراء</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map((r, i) => (
                <tr key={r.id} style={{ borderBottom: '1px solid #f3f4f6' }}>
                  <td style={tdStyle}>{i + 1}</td>
                  <td style={tdStyle}>
                    <div style={{ fontWeight: 600 }}>{r.studentName}</div>
                    <div style={{ fontSize: '12px', color: '#9ca3af' }}>{r.studentNumber}</div>
                  </td>
                  <td style={tdStyle}>{r.grade} / {r.className}</td>
                  <td style={tdStyle}>{r.exitTime || '-'}</td>
                  <td style={tdStyle}>
                    <span style={{ background: '#f5f3ff', color: '#7c3aed', padding: '4px 10px', borderRadius: '6px', fontSize: '12px', fontWeight: 600 }}>
                      {r.reason || '-'}
                    </span>
                  </td>
                  <td style={tdStyle}>{r.receiver || '-'}</td>
                  <td style={tdStyle}>{r.hijriDate || new Date(r.recordedAt).toLocaleDateString('ar-SA')}</td>
                  <td style={tdStyle}>
                    <button onClick={() => setConfirmDelete(r)} style={{
                      background: '#fee2e2', color: '#dc2626', border: 'none',
                      borderRadius: '6px', padding: '4px 12px', fontSize: '12px', fontWeight: 600, cursor: 'pointer',
                    }}>حذف</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {modalOpen && <AddPermissionModal stages={enabledStages} onClose={() => setModalOpen(false)} onSaved={() => { setModalOpen(false); loadData(); }} />}

      {confirmDelete && (
        <div style={overlayStyle}>
          <div style={{ background: '#fff', borderRadius: '16px', padding: '32px', maxWidth: '400px', width: '90%' }}>
            <h3 style={{ margin: '0 0 16px', fontSize: '18px', fontWeight: 700 }}>تأكيد الحذف</h3>
            <p>هل تريد حذف سجل الاستئذان للطالب <strong>{confirmDelete.studentName}</strong>؟</p>
            <div style={{ display: 'flex', gap: '8px', justifyContent: 'flex-end', marginTop: '24px' }}>
              <button onClick={() => setConfirmDelete(null)} style={{ padding: '8px 20px', border: '1px solid #d1d5db', borderRadius: '8px', background: '#fff', cursor: 'pointer' }}>إلغاء</button>
              <button onClick={handleDelete} style={{ padding: '8px 20px', background: '#dc2626', color: '#fff', border: 'none', borderRadius: '8px', fontWeight: 700, cursor: 'pointer' }}>حذف</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

// ─── Add Modal ───
interface AddModalProps { stages: StageConfigData[]; onClose: () => void; onSaved: () => void; }

const AddPermissionModal: React.FC<AddModalProps> = ({ onClose, onSaved }) => {
  const [students, setStudents] = useState<StudentOption[]>([]);
  const [studentSearch, setStudentSearch] = useState('');
  const [selectedStudent, setSelectedStudent] = useState<StudentOption | null>(null);
  const [exitTime, setExitTime] = useState('');
  const [reason, setReason] = useState('');
  const [receiver, setReceiver] = useState('');
  const [supervisor, setSupervisor] = useState('');
  const [hijriDate, setHijriDate] = useState('');
  const [saving, setSaving] = useState(false);

  useEffect(() => { studentsApi.getAll().then(res => { if (res.data?.data) setStudents(res.data.data); }); }, []);

  const filteredStudents = useMemo(() => {
    if (!studentSearch.trim()) return [];
    const q = studentSearch.trim().toLowerCase();
    return students.filter(s => s.name.toLowerCase().includes(q) || s.studentNumber.includes(q)).slice(0, 10);
  }, [students, studentSearch]);

  const handleSave = async () => {
    if (!selectedStudent) return showError('اختر الطالب');
    setSaving(true);
    try {
      const data: PermissionData = { studentId: selectedStudent.id, exitTime, reason, receiver, supervisor, hijriDate };
      const res = await permissionsApi.add(data);
      if (res.data?.success) { showSuccess('تم تسجيل الاستئذان بنجاح'); onSaved(); }
      else showError(res.data?.message || 'فشل التسجيل');
    } catch { showError('فشل التسجيل'); }
    finally { setSaving(false); }
  };

  return (
    <div style={overlayStyle}>
      <div style={{ background: '#fff', borderRadius: '16px', padding: '32px', maxWidth: '500px', width: '95%', maxHeight: '90vh', overflowY: 'auto' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
          <h2 style={{ margin: 0, fontSize: '20px', fontWeight: 800 }}>تسجيل استئذان</h2>
          <button onClick={onClose} style={{ background: 'none', border: 'none', fontSize: '24px', cursor: 'pointer', color: '#9ca3af' }}>x</button>
        </div>

        <label style={labelStyle}>الطالب</label>
        {selectedStudent ? (
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '16px', padding: '10px', background: '#f5f3ff', borderRadius: '8px', border: '1px solid #ddd6fe' }}>
            <span style={{ fontWeight: 700 }}>{selectedStudent.name}</span>
            <span style={{ fontSize: '12px', color: '#6b7280' }}>{selectedStudent.studentNumber}</span>
            <button onClick={() => { setSelectedStudent(null); setStudentSearch(''); }}
              style={{ marginRight: 'auto', background: 'none', border: 'none', cursor: 'pointer', color: '#dc2626' }}>x</button>
          </div>
        ) : (
          <div style={{ position: 'relative', marginBottom: '16px' }}>
            <input type="text" placeholder="ابحث عن طالب..." value={studentSearch} onChange={e => setStudentSearch(e.target.value)} style={inputStyle} />
            {filteredStudents.length > 0 && (
              <div style={{ position: 'absolute', top: '100%', right: 0, left: 0, background: '#fff', border: '1px solid #d1d5db', borderRadius: '8px', maxHeight: '200px', overflowY: 'auto', zIndex: 10 }}>
                {filteredStudents.map(s => (
                  <div key={s.id} onClick={() => { setSelectedStudent(s); setStudentSearch(''); }}
                    style={{ padding: '10px 12px', cursor: 'pointer', borderBottom: '1px solid #f3f4f6', fontSize: '14px' }}>
                    <strong>{s.name}</strong> <span style={{ color: '#6b7280' }}>{s.studentNumber}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        <label style={labelStyle}>وقت الخروج</label>
        <input type="time" value={exitTime} onChange={e => setExitTime(e.target.value)} style={inputStyle} />

        <label style={labelStyle}>السبب</label>
        <div style={{ display: 'flex', gap: '6px', marginBottom: '16px', flexWrap: 'wrap' }}>
          {REASONS.map(r => (
            <button key={r} onClick={() => setReason(r)}
              style={{
                padding: '8px 14px', borderRadius: '8px', fontSize: '12px', fontWeight: 600, cursor: 'pointer',
                background: reason === r ? '#7c3aed' : '#f3f4f6',
                color: reason === r ? '#fff' : '#374151',
                border: reason === r ? '2px solid #6d28d9' : '1px solid #d1d5db',
              }}>{r}</button>
          ))}
        </div>

        <label style={labelStyle}>المستلم</label>
        <input type="text" value={receiver} onChange={e => setReceiver(e.target.value)} style={inputStyle} placeholder="اسم ولي الأمر أو المستلم" />

        <label style={labelStyle}>المسؤول</label>
        <input type="text" value={supervisor} onChange={e => setSupervisor(e.target.value)} style={inputStyle} placeholder="اسم المشرف أو المسؤول" />

        <label style={labelStyle}>التاريخ الهجري (اختياري)</label>
        <input type="text" value={hijriDate} onChange={e => setHijriDate(e.target.value)} style={inputStyle} placeholder="1446/08/15" />

        <button onClick={handleSave} disabled={saving}
          style={{
            width: '100%', padding: '12px', background: '#7c3aed', color: '#fff',
            border: 'none', borderRadius: '10px', fontWeight: 700, fontSize: '16px',
            cursor: saving ? 'not-allowed' : 'pointer', opacity: saving ? 0.6 : 1, marginTop: '8px',
          }}>
          {saving ? 'جاري الحفظ...' : 'حفظ'}
        </button>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ label: string; value: number; color: string }> = ({ label, value, color }) => (
  <div style={{ background: '#fff', borderRadius: '12px', padding: '20px', border: '1px solid #e5e7eb' }}>
    <div style={{ fontSize: '12px', color: '#6b7280', marginBottom: '4px' }}>{label}</div>
    <div style={{ fontSize: '28px', fontWeight: 800, color }}>{value}</div>
  </div>
);

const overlayStyle: React.CSSProperties = { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000 };
const filterBtnStyle = (active: boolean): React.CSSProperties => ({
  padding: '8px 16px', borderRadius: '8px', border: active ? '2px solid #7c3aed' : '1px solid #d1d5db',
  background: active ? '#f5f3ff' : '#fff', color: active ? '#7c3aed' : '#374151',
  fontWeight: active ? 700 : 400, fontSize: '13px', cursor: 'pointer',
});
const thStyle: React.CSSProperties = { padding: '12px 16px', textAlign: 'right', fontWeight: 700, fontSize: '13px', color: '#374151' };
const tdStyle: React.CSSProperties = { padding: '12px 16px', textAlign: 'right' };
const labelStyle: React.CSSProperties = { display: 'block', fontSize: '13px', fontWeight: 700, color: '#374151', marginBottom: '6px' };
const inputStyle: React.CSSProperties = { width: '100%', padding: '10px 14px', border: '1px solid #d1d5db', borderRadius: '8px', fontSize: '14px', marginBottom: '16px', boxSizing: 'border-box' };

export default PermissionsPage;
