import api from './client';

export interface PermissionData {
  studentId: number;
  exitTime?: string;
  reason?: string;
  receiver?: string;
  supervisor?: string;
  hijriDate?: string;
  recordedBy?: string;
}

export const permissionsApi = {
  getAll: (stage?: string, grade?: string, className?: string, studentId?: number, hijriDate?: string) => {
    const params = new URLSearchParams();
    if (stage) params.set('stage', stage);
    if (grade) params.set('grade', grade);
    if (className) params.set('className', className);
    if (studentId) params.set('studentId', studentId.toString());
    if (hijriDate) params.set('hijriDate', hijriDate);
    return api.get(`/permissions?${params.toString()}`);
  },
  add: (data: PermissionData) => api.post('/permissions', data),
  update: (id: number, data: Partial<PermissionData>) => api.put(`/permissions/${id}`, data),
  delete: (id: number) => api.delete(`/permissions/${id}`),
  getStudentCount: (studentId: number) => api.get(`/permissions/student-count/${studentId}`),
};
