import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { dashboardApi } from '../api/dashboard';
import { settingsApi, StageConfigData } from '../api/settings';
import { SETTINGS_STAGES } from '../utils/constants';

const DEGREE_COLORS: Record<number, { label: string; color: string; bg: string }> = {
  1: { label: 'الأولى', color: '#15803d', bg: '#dcfce7' },
  2: { label: 'الثانية', color: '#ca8a04', bg: '#fef9c3' },
  3: { label: 'الثالثة', color: '#ea580c', bg: '#ffedd5' },
  4: { label: 'الرابعة', color: '#dc2626', bg: '#fee2e2' },
  5: { label: 'الخامسة', color: '#7c2d12', bg: '#fecaca' },
};

interface DashboardData {
  students: { total: number };
  violations: { total: number; totalDeduction: number; byDegree: { degree: number; count: number }[] };
  positive: { total: number };
  tardiness: { total: number; byType: { type: string; count: number }[] };
  absence: { total: number; byType: { type: string; count: number }[]; pending: number };
  permissions: { total: number };
  notes: { total: number; byType: { type: string; count: number }[] };
  recentActivity: { type: string; studentName: string; detail: string; degree: number; deduction: number; recordedAt: string }[];
  topViolators: { studentId: number; studentName: string; studentNumber: string; count: number; totalDeduction: number }[];
}

const DashboardPage: React.FC = () => {
  const [data, setData] = useState<DashboardData | null>(null);
  const [stages, setStages] = useState<StageConfigData[]>([]);
  const [loading, setLoading] = useState(true);
  const [stageFilter, setStageFilter] = useState('');

  const enabledStages = useMemo(() =>
    stages.filter((s) => s.isEnabled && s.grades.some((g) => g.isEnabled && g.classCount > 0)),
    [stages]
  );

  const loadData = useCallback(async () => {
    setLoading(true);
    try {
      const [dRes, sRes] = await Promise.all([
        dashboardApi.get(stageFilter || undefined),
        settingsApi.getStructure(),
      ]);
      if (dRes.data?.data) setData(dRes.data.data);
      if (sRes.data?.data?.stages) {
        const raw = sRes.data.data.stages;
        setStages(Array.isArray(raw) ? raw : Object.values(raw));
      }
    } catch { /* empty */ }
    finally { setLoading(false); }
  }, [stageFilter]);

  useEffect(() => { loadData(); }, [loadData]);

  const stageLabel = (id: string) => SETTINGS_STAGES.find(s => s.id === id)?.name || id;

  if (loading) {
    return <div style={{ textAlign: 'center', padding: '80px', color: '#9ca3af' }}>جاري التحميل...</div>;
  }

  if (!data) {
    return <div style={{ textAlign: 'center', padding: '80px', color: '#9ca3af' }}>لا توجد بيانات</div>;
  }

  return (
    <div>
      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
        <h1 style={{ fontSize: '24px', fontWeight: 800, color: '#111', margin: 0 }}>لوحة التحكم</h1>
        <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
          <button onClick={() => setStageFilter('')}
            style={filterBtnStyle(!stageFilter)}>الكل</button>
          {enabledStages.map(s => (
            <button key={s.stage} onClick={() => setStageFilter(s.stage)}
              style={filterBtnStyle(stageFilter === s.stage)}>{stageLabel(s.stage)}</button>
          ))}
        </div>
      </div>

      {/* Main Stats Grid */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '16px', marginBottom: '24px' }}>
        <BigStatCard icon="👨‍🎓" label="إجمالي الطلاب" value={data.students.total} color="#4f46e5" bg="#eef2ff" />
        <BigStatCard icon="⚠️" label="المخالفات" value={data.violations.total} color="#dc2626" bg="#fef2f2" />
        <BigStatCard icon="⭐" label="السلوك الإيجابي" value={data.positive.total} color="#16a34a" bg="#f0fdf4" />
        <BigStatCard icon="⏰" label="التأخر" value={data.tardiness.total} color="#ea580c" bg="#fff7ed" />
        <BigStatCard icon="📋" label="الغياب" value={data.absence.total} color="#dc2626" bg="#fef2f2" />
        <BigStatCard icon="🚪" label="الاستئذان" value={data.permissions.total} color="#7c3aed" bg="#f5f3ff" />
        <BigStatCard icon="📝" label="الملاحظات" value={data.notes.total} color="#2563eb" bg="#eff6ff" />
        <BigStatCard icon="📉" label="إجمالي الحسم" value={data.violations.totalDeduction} color="#991b1b" bg="#fef2f2" suffix=" درجة" />
      </div>

      {/* Two Column Layout */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px', marginBottom: '24px' }}>
        {/* المخالفات حسب الدرجة */}
        <div style={cardStyle}>
          <h3 style={cardTitleStyle}>المخالفات حسب الدرجة</h3>
          {data.violations.byDegree.length === 0 ? (
            <p style={{ color: '#9ca3af', textAlign: 'center', padding: '20px' }}>لا توجد مخالفات</p>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
              {data.violations.byDegree.map(d => {
                const dc = DEGREE_COLORS[d.degree] || { label: `${d.degree}`, color: '#374151', bg: '#f3f4f6' };
                const maxCount = Math.max(...data.violations.byDegree.map(x => x.count), 1);
                return (
                  <div key={d.degree} style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                    <span style={{
                      minWidth: '60px', padding: '4px 8px', borderRadius: '6px', fontSize: '12px',
                      fontWeight: 700, textAlign: 'center', background: dc.bg, color: dc.color,
                    }}>{dc.label}</span>
                    <div style={{ flex: 1, background: '#f3f4f6', borderRadius: '6px', height: '24px', overflow: 'hidden' }}>
                      <div style={{
                        width: `${(d.count / maxCount) * 100}%`, height: '100%',
                        background: dc.color, borderRadius: '6px', minWidth: d.count > 0 ? '24px' : 0,
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        color: '#fff', fontSize: '11px', fontWeight: 700,
                      }}>{d.count}</div>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* الغياب المعلق */}
        <div style={cardStyle}>
          <h3 style={cardTitleStyle}>ملخص الغياب</h3>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
            <MiniStat label="يوم كامل" value={data.absence.byType.find(t => t.type === 'FullDay')?.count || 0} color="#dc2626" />
            <MiniStat label="غياب حصة" value={data.absence.byType.find(t => t.type === 'Period')?.count || 0} color="#ea580c" />
            <MiniStat label="معلق" value={data.absence.pending} color="#ca8a04" />
            <MiniStat label="إجمالي" value={data.absence.total} color="#374151" />
          </div>
        </div>
      </div>

      {/* Bottom Two Columns */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
        {/* آخر الأحداث */}
        <div style={cardStyle}>
          <h3 style={cardTitleStyle}>آخر الأحداث</h3>
          {data.recentActivity.length === 0 ? (
            <p style={{ color: '#9ca3af', textAlign: 'center', padding: '20px' }}>لا توجد أحداث</p>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '0' }}>
              {data.recentActivity.map((a, i) => (
                <div key={i} style={{
                  display: 'flex', alignItems: 'center', gap: '12px',
                  padding: '10px 0', borderBottom: i < data.recentActivity.length - 1 ? '1px solid #f3f4f6' : 'none',
                }}>
                  <span style={{
                    width: '32px', height: '32px', borderRadius: '8px', display: 'flex',
                    alignItems: 'center', justifyContent: 'center', fontSize: '16px',
                    background: a.type === 'violation' ? '#fee2e2' : '#dcfce7',
                  }}>
                    {a.type === 'violation' ? '⚠️' : '⭐'}
                  </span>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontWeight: 600, fontSize: '13px', color: '#111' }}>{a.studentName}</div>
                    <div style={{ fontSize: '12px', color: '#6b7280', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{a.detail}</div>
                  </div>
                  {a.type === 'violation' && a.degree > 0 && (
                    <span style={{
                      padding: '2px 8px', borderRadius: '6px', fontSize: '11px', fontWeight: 700,
                      background: (DEGREE_COLORS[a.degree] || {}).bg || '#f3f4f6',
                      color: (DEGREE_COLORS[a.degree] || {}).color || '#374151',
                    }}>-{a.deduction}</span>
                  )}
                  <span style={{ fontSize: '11px', color: '#9ca3af', whiteSpace: 'nowrap' }}>
                    {new Date(a.recordedAt).toLocaleDateString('ar-SA')}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* أكثر الطلاب مخالفات */}
        <div style={cardStyle}>
          <h3 style={cardTitleStyle}>أكثر الطلاب مخالفات</h3>
          {data.topViolators.length === 0 ? (
            <p style={{ color: '#9ca3af', textAlign: 'center', padding: '20px' }}>لا توجد بيانات</p>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '0' }}>
              {data.topViolators.map((s, i) => (
                <div key={s.studentId} style={{
                  display: 'flex', alignItems: 'center', gap: '12px',
                  padding: '10px 0', borderBottom: i < data.topViolators.length - 1 ? '1px solid #f3f4f6' : 'none',
                }}>
                  <span style={{
                    width: '28px', height: '28px', borderRadius: '50%', display: 'flex',
                    alignItems: 'center', justifyContent: 'center', fontSize: '13px', fontWeight: 800,
                    background: i === 0 ? '#fee2e2' : i === 1 ? '#fef9c3' : '#f3f4f6',
                    color: i === 0 ? '#dc2626' : i === 1 ? '#ca8a04' : '#6b7280',
                  }}>{i + 1}</span>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontWeight: 600, fontSize: '13px' }}>{s.studentName}</div>
                    <div style={{ fontSize: '11px', color: '#9ca3af' }}>{s.studentNumber}</div>
                  </div>
                  <div style={{ textAlign: 'left' }}>
                    <div style={{ fontSize: '14px', fontWeight: 800, color: '#dc2626' }}>{s.count}</div>
                    <div style={{ fontSize: '11px', color: '#9ca3af' }}>-{s.totalDeduction} درجة</div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

// ─── Components ───
const BigStatCard: React.FC<{ icon: string; label: string; value: number; color: string; bg: string; suffix?: string }> = ({ icon, label, value, color, bg, suffix }) => (
  <div style={{ background: '#fff', borderRadius: '14px', padding: '20px', border: '1px solid #e5e7eb', display: 'flex', alignItems: 'center', gap: '16px' }}>
    <div style={{ width: '48px', height: '48px', borderRadius: '12px', background: bg, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '24px' }}>
      {icon}
    </div>
    <div>
      <div style={{ fontSize: '12px', color: '#6b7280', marginBottom: '2px' }}>{label}</div>
      <div style={{ fontSize: '24px', fontWeight: 800, color }}>{value}{suffix || ''}</div>
    </div>
  </div>
);

const MiniStat: React.FC<{ label: string; value: number; color: string }> = ({ label, value, color }) => (
  <div style={{ background: '#f9fafb', borderRadius: '10px', padding: '14px', textAlign: 'center' }}>
    <div style={{ fontSize: '11px', color: '#6b7280', marginBottom: '4px' }}>{label}</div>
    <div style={{ fontSize: '22px', fontWeight: 800, color }}>{value}</div>
  </div>
);

const cardStyle: React.CSSProperties = { background: '#fff', borderRadius: '14px', padding: '20px', border: '1px solid #e5e7eb' };
const cardTitleStyle: React.CSSProperties = { fontSize: '16px', fontWeight: 800, color: '#111', margin: '0 0 16px' };
const filterBtnStyle = (active: boolean): React.CSSProperties => ({
  padding: '8px 16px', borderRadius: '8px', border: active ? '2px solid #4f46e5' : '1px solid #d1d5db',
  background: active ? '#eef2ff' : '#fff', color: active ? '#4f46e5' : '#374151',
  fontWeight: active ? 700 : 400, fontSize: '13px', cursor: 'pointer',
});

export default DashboardPage;
