import React, { useState, useEffect } from 'react';
import { communicationApi } from '../api/communication';

interface WhatsAppSession {
  id: number;
  phoneNumber: string;
  stage: string;
  userType: string;
  connectionStatus: string;
  linkedAt: string | null;
  lastUsed: string | null;
  messageCount: number;
  isPrimary: boolean;
}

const STATUS_STYLES: Record<string, { label: string; color: string; bg: string }> = {
  'متصل': { label: 'متصل', color: '#16a34a', bg: '#dcfce7' },
  'غير متصل': { label: 'غير متصل', color: '#dc2626', bg: '#fee2e2' },
  'قيد الربط': { label: 'قيد الربط', color: '#ca8a04', bg: '#fef9c3' },
};

const WhatsAppPage: React.FC = () => {
  const [sessions, setSessions] = useState<WhatsAppSession[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadSessions();
  }, []);

  const loadSessions = async () => {
    setLoading(true);
    try {
      const res = await communicationApi.getWhatsAppSessions();
      if (res.data?.data) setSessions(res.data.data);
    } catch { /* empty */ }
    finally { setLoading(false); }
  };

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
        <h1 style={{ fontSize: '24px', fontWeight: 800, color: '#111', margin: 0 }}>الواتساب</h1>
        <button onClick={loadSessions} style={{
          padding: '10px 20px', background: '#25d366', color: '#fff', border: 'none',
          borderRadius: '10px', fontWeight: 700, fontSize: '14px', cursor: 'pointer',
        }}>تحديث الحالة</button>
      </div>

      {/* Stats */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '16px', marginBottom: '24px' }}>
        <StatCard label="إجمالي الجلسات" value={sessions.length} color="#25d366" />
        <StatCard label="متصل" value={sessions.filter(s => s.connectionStatus === 'متصل').length} color="#16a34a" />
        <StatCard label="إجمالي الرسائل" value={sessions.reduce((a, s) => a + s.messageCount, 0)} color="#2563eb" />
      </div>

      {/* Sessions */}
      {loading ? (
        <div style={{ textAlign: 'center', padding: '40px', color: '#9ca3af' }}>جاري التحميل...</div>
      ) : sessions.length === 0 ? (
        <div style={{ background: '#fff', borderRadius: '16px', padding: '48px', textAlign: 'center', border: '1px solid #e5e7eb' }}>
          <div style={{ fontSize: '48px', marginBottom: '16px' }}>💬</div>
          <h3 style={{ fontSize: '18px', fontWeight: 700, color: '#374151', marginBottom: '8px' }}>لا توجد جلسات واتساب</h3>
          <p style={{ color: '#9ca3af', fontSize: '14px' }}>
            سيتم عرض جلسات الواتساب المربوطة هنا بعد تهيئة خدمة الواتساب
          </p>
        </div>
      ) : (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))', gap: '16px' }}>
          {sessions.map(session => {
            const st = STATUS_STYLES[session.connectionStatus] || { label: session.connectionStatus, color: '#6b7280', bg: '#f3f4f6' };
            return (
              <div key={session.id} style={{
                background: '#fff', borderRadius: '14px', padding: '20px',
                border: session.isPrimary ? '2px solid #25d366' : '1px solid #e5e7eb',
              }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                    <div style={{
                      width: '40px', height: '40px', borderRadius: '50%', background: '#dcfce7',
                      display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '20px',
                    }}>💬</div>
                    <div>
                      <div style={{ fontWeight: 700, fontSize: '15px', direction: 'ltr' as const }}>{session.phoneNumber || 'غير محدد'}</div>
                      <div style={{ fontSize: '12px', color: '#6b7280' }}>{session.userType} - {session.stage}</div>
                    </div>
                  </div>
                  <span style={{
                    padding: '4px 12px', borderRadius: '20px', fontSize: '12px', fontWeight: 700,
                    background: st.bg, color: st.color,
                  }}>{st.label}</span>
                </div>

                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px' }}>
                  <div style={{ background: '#f9fafb', borderRadius: '8px', padding: '10px', textAlign: 'center' }}>
                    <div style={{ fontSize: '11px', color: '#6b7280' }}>الرسائل</div>
                    <div style={{ fontSize: '18px', fontWeight: 800, color: '#111' }}>{session.messageCount}</div>
                  </div>
                  <div style={{ background: '#f9fafb', borderRadius: '8px', padding: '10px', textAlign: 'center' }}>
                    <div style={{ fontSize: '11px', color: '#6b7280' }}>آخر استخدام</div>
                    <div style={{ fontSize: '12px', fontWeight: 600, color: '#374151' }}>
                      {session.lastUsed ? new Date(session.lastUsed).toLocaleDateString('ar-SA') : '-'}
                    </div>
                  </div>
                </div>

                {session.isPrimary && (
                  <div style={{
                    marginTop: '12px', textAlign: 'center', fontSize: '12px',
                    color: '#16a34a', fontWeight: 700, background: '#f0fdf4',
                    padding: '6px', borderRadius: '6px',
                  }}>الجلسة الأساسية</div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

const StatCard: React.FC<{ label: string; value: number; color: string }> = ({ label, value, color }) => (
  <div style={{ background: '#fff', borderRadius: '12px', padding: '20px', border: '1px solid #e5e7eb' }}>
    <div style={{ fontSize: '12px', color: '#6b7280', marginBottom: '4px' }}>{label}</div>
    <div style={{ fontSize: '28px', fontWeight: 800, color }}>{value}</div>
  </div>
);

export default WhatsAppPage;
