import api from './client';

export const communicationApi = {
  getAll: (stage?: string, messageType?: string, studentId?: number) => {
    const params = new URLSearchParams();
    if (stage) params.set('stage', stage);
    if (messageType) params.set('messageType', messageType);
    if (studentId) params.set('studentId', studentId.toString());
    return api.get(`/communication?${params.toString()}`);
  },
  getSummary: () => api.get('/communication/summary'),
  getWhatsAppSessions: () => api.get('/communication/whatsapp/sessions'),
};
