import React from 'react';
import { NavLink } from 'react-router-dom';

interface Props {
  open: boolean;
  role?: string;
}

interface NavItem {
  path: string;
  label: string;
  icon: string;
  roles?: string[]; // if undefined, visible to all
}

interface NavGroup {
  section: string;
  items: NavItem[];
}

const NAV_ITEMS: NavGroup[] = [
  { section: 'الرئيسية', items: [
    { path: '/', label: 'لوحة التحكم', icon: '📊' },
  ]},
  { section: 'شؤون الطلاب', items: [
    { path: '/violations', label: 'المخالفات السلوكية', icon: '⚠️' },
    { path: '/positive', label: 'السلوك الإيجابي', icon: '⭐' },
    { path: '/tardiness', label: 'التأخر', icon: '⏰', roles: ['Admin', 'Deputy', 'Counselor', 'Guard'] },
    { path: '/absence', label: 'الغياب', icon: '📋', roles: ['Admin', 'Deputy', 'Counselor'] },
    { path: '/permissions', label: 'الاستئذان', icon: '🚪', roles: ['Admin', 'Deputy', 'Counselor', 'Guard'] },
    { path: '/notes', label: 'الملاحظات التربوية', icon: '📝' },
  ]},
  { section: 'التواصل', items: [
    { path: '/whatsapp', label: 'الواتساب', icon: '💬', roles: ['Admin', 'Deputy'] },
    { path: '/communication', label: 'سجل التواصل', icon: '📞', roles: ['Admin', 'Deputy', 'Counselor'] },
  ]},
  { section: 'النظام', items: [
    { path: '/settings', label: 'الإعدادات', icon: '⚙️', roles: ['Admin'] },
  ]},
];

const Sidebar: React.FC<Props> = ({ open, role }) => {
  if (!open) return null;

  const visibleGroups = NAV_ITEMS.map(group => ({
    ...group,
    items: group.items.filter(item => !item.roles || (role && item.roles.includes(role))),
  })).filter(group => group.items.length > 0);

  return (
    <aside style={{
      width: '240px', minWidth: '240px', height: '100vh',
      background: '#fff', borderLeft: '1px solid #e5e7eb',
      display: 'flex', flexDirection: 'column', overflowY: 'auto',
    }}>
      {/* Logo */}
      <div style={{
        padding: '16px 20px', borderBottom: '1px solid #e5e7eb',
        display: 'flex', alignItems: 'center', gap: '12px',
      }}>
        <div style={{
          width: '40px', height: '40px', background: '#4f46e5', borderRadius: '12px',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          color: '#fff', fontWeight: 800, fontSize: '18px',
        }}>
          ش
        </div>
        <div>
          <div style={{ fontWeight: 800, fontSize: '14px', color: '#111' }}>شؤون الطلاب</div>
          <div style={{ fontSize: '11px', color: '#9ca3af' }}>نظام إدارة السلوك</div>
        </div>
      </div>

      {/* Navigation */}
      <nav style={{ padding: '12px', flex: 1 }}>
        {visibleGroups.map((group) => (
          <div key={group.section}>
            <div style={{
              fontSize: '11px', fontWeight: 700, color: '#9ca3af',
              textTransform: 'uppercase', letterSpacing: '0.05em',
              margin: '16px 8px 8px', padding: 0,
            }}>
              {group.section}
            </div>
            {group.items.map((item) => (
              <NavLink
                key={item.path}
                to={item.path}
                end={item.path === '/'}
                style={({ isActive }) => ({
                  display: 'flex', alignItems: 'center', gap: '12px',
                  padding: '10px 12px', borderRadius: '8px',
                  textDecoration: 'none', fontSize: '14px',
                  color: isActive ? '#4338ca' : '#374151',
                  background: isActive ? '#eef2ff' : 'transparent',
                  fontWeight: isActive ? 700 : 400,
                  marginBottom: '2px',
                  transition: 'all 0.15s',
                })}
              >
                <span style={{ fontSize: '18px' }}>{item.icon}</span>
                <span>{item.label}</span>
              </NavLink>
            ))}
          </div>
        ))}
      </nav>
    </aside>
  );
};

export default Sidebar;
