import api from './client';

export interface ViolationData {
  studentId: number;
  violationCode?: string;
  description?: string;
  type?: string;
  degree: number;
  hijriDate?: string;
  miladiDate?: string;
  recordedBy?: string;
  notes?: string;
}

export interface RepetitionInfo {
  currentCount: number;
  nextRepetition: number;
  deduction: number;
  procedures: string[];
}

export const violationsApi = {
  getAll: (stage?: string, grade?: string, className?: string, studentId?: number) => {
    const params = new URLSearchParams();
    if (stage) params.set('stage', stage);
    if (grade) params.set('grade', grade);
    if (className) params.set('className', className);
    if (studentId) params.set('studentId', studentId.toString());
    return api.get(`/violations?${params.toString()}`);
  },
  getRepetition: (studentId: number, degree: number) =>
    api.get(`/violations/repetition?studentId=${studentId}&degree=${degree}`),
  add: (data: ViolationData) => api.post('/violations', data),
  update: (id: number, data: Partial<ViolationData>) => api.put(`/violations/${id}`, data),
  delete: (id: number) => api.delete(`/violations/${id}`),
  getTypes: () => api.get('/violations/types'),
  getStudentSummary: (studentId: number) => api.get(`/violations/student-summary/${studentId}`),
};
